+function hasCodexConfigOverride(args: string[], key: string): boolean {
+  for (let i = 0; i < args.length; i += 1) {
+    if (args[i] !== "-c" && args[i] !== "--config") continue;
+    const next = args[i + 1] ?? "";
+    if (next.trim().startsWith(`${key}=`)) return true;
+  }
+  return false;
